package javapackage;

public class whileloop1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int i = 10; 
		
		while (i < 20 & i < 12) {
			System.out.println(i);
			i++; // If we forget to give this condition program will run in infinite loop
		}
	}

}
